const posts = $input.all();
const results = [];

for (const post of posts) {
  const p = post.json;
  if (p.error || !p.id) continue;

  const handle = p.ownerUsername || (p.owner && p.owner.username) || 'unknown';
  const caption = (p.caption || '').trim();
  const lines = caption.split('\n').filter(l => l.trim().length > 0);
  const firstLine = lines[0] || '';
  const hookText = firstLine.length >= 20 ? firstLine : (caption.split('.')[0] || firstLine);

  if (!hookText || hookText.length < 5) continue;

  let format = 'feed';
  if (p.type === 'Video') format = 'reel';
  else if (p.type === 'Sidecar') format = 'carousel';

  results.push({
    json: {
      post_id: String(p.id || p.shortCode || ''),
      post_url: p.url || ('https://www.instagram.com/p/' + (p.shortCode || '')),
      platform: 'instagram',
      source_account: handle,
      hook_text: hookText.substring(0, 500),
      full_caption: caption.substring(0, 1000),
      format: format,
      likes: p.likesCount || 0,
      comments: p.commentsCount || 0,
      views: null,
      posted_at: p.timestamp || null
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const response = item.json;
  // Get handle from pairedItem chain back to Is Instagram? node
  let handle = 'unknown';
  try { handle = $('Is Instagram?').item.json.handle; } catch(e) {}

  for (const video of (response.items || [])) {
    const stats = video.statistics || {};
    const snippet = video.snippet || {};
    const title = (snippet.title || '').trim();
    if (!title) continue;

    results.push({
      json: {
        post_id: String(video.id),
        post_url: 'https://www.youtube.com/watch?v=' + video.id,
        platform: 'youtube',
        source_account: handle,
        hook_text: title.substring(0, 500),
        full_caption: (snippet.description || '').substring(0, 1000),
        format: 'video',
        likes: parseInt(stats.likeCount || 0),
        comments: parseInt(stats.commentCount || 0),
        views: parseInt(stats.viewCount || 0),
        posted_at: snippet.publishedAt || null
      }
    });
  }
}

return results;

return $input.all().map(item => {
  const post = item.json;
  const text = (post.hook_text || '').toLowerCase();

  let hookType = 'curiosity_gap';
  let tone = 'emocional';
  let confidence = 0.55;

  if (/\?/.test(post.hook_text || '')) {
    hookType = 'question'; tone = 'filosofico'; confidence = 0.82;
  } else if (/\b(wrong|errado|para de|stop doing|stop using|you're doing it|voce ta errado|erro que|nunca fa|don't do|nao faca|mistake|erro)\b/.test(text)) {
    hookType = 'attack'; tone = 'provocativo'; confidence = 0.76;
  } else if (/\b(but |mas |however|porem|actually|na verdade|contrary|contrario|despite|apesar|isn't|nao e|not what)\b/.test(text)) {
    hookType = 'contradiction'; tone = 'polarizador'; confidence = 0.72;
  } else if (/\b(secret|segredo|never told|nunca contei|confession|confess|revealing|revelando|truth about|real reason|hidden|escondido)\b/.test(text)) {
    hookType = 'reveal'; tone = 'emocional'; confidence = 0.78;
  } else if (/\b(you also|voce tambem|you too|ever feel|ever notice|have you|ja sentiu|ja passou|recognize|reconhece|relate|sound familiar)\b/.test(text)) {
    hookType = 'mirror'; tone = 'emocional'; confidence = 0.70;
  } else if (/\b(client|cliente|result|resultado|transform|proof|prova|people|pessoas|students|alunos|helped|ajudei|\$[0-9]|[0-9]+k|[0-9]+m|percent|%)\b/.test(text)) {
    hookType = 'social_proof'; tone = 'autoritario'; confidence = 0.73;
  } else if (/\b(never again|nunca mais|i believe|acredito|my truth|minha verdade|promise|prometo|always|sempre|principle|principio|manifesto|vow)\b/.test(text)) {
    hookType = 'manifesto'; tone = 'filosofico'; confidence = 0.65;
  }

  return { json: { ...post, hook_type: hookType, tone: tone, classification_confidence: confidence, auto_classified: true } };
});
